3	const PROCESSING_FEE = 5;
4	const FIRST_INSURANCE_SURCHARGE = 0.1;
5	
6	const BASE_PREMIUMS: Record<string, number> = {
7	  sword: 100,
8	  amulet: 60,
9	  staff: 80,
10	  potion: 40,
11	  rune: 25,
12	};
13	
14	type Item = { type: string };
15	type Step = { op: string; items: Item[] };
16	type Scenario = { steps: Step[] };
17	
18	const itemBasePremium = (item: Item): number => BASE_PREMIUMS[item.type] ?? 0;
19	
20	const sumItemBasePremiums = (items: Item[]): number =>
21	  items.reduce((sum, item) => sum + itemBasePremium(item), 0);
22	
23	export function runScenario(scenario: unknown): { results: { premium: number }[] } {
24	  const step = (scenario as Scenario).steps[0];
25	  const itemsBase = sumItemBasePremiums(step.items);
26	  const policyBase = itemsBase + itemsBase * FIRST_INSURANCE_SURCHARGE;
27	  const premium = Math.ceil(policyBase + PROCESSING_FEE);
28	  return { results: [{ premium }] };
29	}
